package com.inyaw.sys.controller;import com.inyaw.base.BaseResult;import com.inyaw.sys.bean.InyawSysDept;import com.inyaw.sys.dto.InyawSysDeptDto;import com.inyaw.sys.service.InyawSysDeptService;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController@RequestMapping("/dept")@RequiredArgsConstructorpublic class InyawSysDeptController {    private final InyawSysDeptService inyawSysDeptService;    @GetMapping("/list")    public BaseResult<List<InyawSysDeptDto>> list(InyawSysDept dept) {        return BaseResult.success(inyawSysDeptService.findDeptTree(dept));    }    @PostMapping(value = "/save")    public BaseResult<String> save(@RequestBody InyawSysDept dept) {        inyawSysDeptService.save(dept);        return BaseResult.success();    }    @PostMapping(value = "/delete")    public BaseResult<String> delete(@RequestBody InyawSysDept dept) {        inyawSysDeptService.delete(dept);        return BaseResult.success();    }}